it("should apply cursed surcharge only to the cursed item in a multi-item policy — cursed sword (150 G) + plain amulet (60 G) = 210 G + 5 G fee = 215 G", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 215 }] });
});
